import { readFile, writeFile } from "node:fs/promises";
import { createWorkspace, createForks } from "@tigrisdata/agent-kit";
import { put, get } from "@tigrisdata/storage";

function normalizeBucketName(name: string): string {
  return name.toLowerCase().replace(/[^a-z0-9.-]/g, "-");
}

function stringifyError(err: unknown): string {
  if (!err) return "Unknown error";
  const e = err as any;
  const parts: string[] = [];
  const name = e?.name ?? "Error";
  const message = e?.message ?? String(err);
  parts.push(`${name}: ${message}`);
  if (e?.Code) parts.push(`Code=${e.Code}`);
  if (e?.code) parts.push(`code=${e.code}`);
  if (e?.$metadata?.httpStatusCode) parts.push(`httpStatusCode=${e.$metadata.httpStatusCode}`);
  if (e?.statusCode) parts.push(`statusCode=${e.statusCode}`);
  if (e?.cause) {
    const c = e.cause as any;
    const cm = c?.message ?? String(c);
    parts.push(`cause=${c?.name ?? "Error"}: ${cm}`);
    if (c?.Code) parts.push(`cause.Code=${c.Code}`);
    if (c?.$metadata?.httpStatusCode) parts.push(`cause.httpStatusCode=${c.$metadata.httpStatusCode}`);
  }
  try {
    parts.push(`raw=${JSON.stringify(err, Object.getOwnPropertyNames(e))}`);
  } catch {
    // ignore
  }
  return parts.join(" | ");
}

async function main() {
  const trialIdRaw = await readFile("/logs/artifacts/trial_id", "utf-8");
  const trialId = trialIdRaw.trim().toLowerCase();
  if (!trialId) {
    console.error("trial_id is empty");
    process.exit(1);
  }

  const workspaceName = normalizeBucketName(`harbor-ro-${trialId}`);
  console.log(`Creating workspace: ${workspaceName}`);

  const wsResult = await createWorkspace(workspaceName, {
    ttl: { days: 1 },
    enableSnapshots: true,
    credentials: { role: "Editor" },
  });

  if (wsResult.error) {
    console.error("createWorkspace failed:", stringifyError(wsResult.error));
    process.exit(1);
  }
  if (!wsResult.data || !wsResult.data.credentials) {
    console.error("createWorkspace returned no credentials");
    process.exit(1);
  }

  const editorBucket = wsResult.data.bucket;
  const editorCreds = wsResult.data.credentials;
  console.log(`Editor bucket: ${editorBucket}`);

  // Editor write
  const putResult = await put("notes/welcome.txt", "hello readonly", {
    config: {
      bucket: editorBucket,
      accessKeyId: editorCreds.accessKeyId,
      secretAccessKey: editorCreds.secretAccessKey,
    },
  });
  if (putResult.error) {
    console.error("Editor put failed:", stringifyError(putResult.error));
    process.exit(1);
  }
  console.log("Editor wrote notes/welcome.txt");

  // Create ReadOnly fork
  const forkPrefix = normalizeBucketName(`harbor-ro-${trialId}-readonly`);
  console.log(`Creating fork with prefix: ${forkPrefix}`);
  const forksResult = await createForks(editorBucket, 1, {
    prefix: forkPrefix,
    credentials: { role: "ReadOnly" },
  });
  if (forksResult.error) {
    console.error("createForks failed:", stringifyError(forksResult.error));
    process.exit(1);
  }
  if (!forksResult.data || !forksResult.data.forks || !forksResult.data.forks[0]) {
    console.error("createForks returned no forks");
    process.exit(1);
  }
  const fork = forksResult.data.forks[0];
  if (!fork.credentials) {
    console.error("Fork credentials missing");
    process.exit(1);
  }
  const forkBucket = fork.bucket;
  const readonlyCreds = fork.credentials;
  console.log(`Fork bucket: ${forkBucket}`);

  // Attempt forbidden write
  const forbiddenPut = await put("notes/forbidden.txt", "should be rejected", {
    config: {
      bucket: forkBucket,
      accessKeyId: readonlyCreds.accessKeyId,
      secretAccessKey: readonlyCreds.secretAccessKey,
    },
  });
  if (!forbiddenPut.error) {
    console.error("Forbidden write unexpectedly succeeded!");
    process.exit(1);
  }
  const denial = stringifyError(forbiddenPut.error);
  if (!denial) {
    console.error("Denial error stringified to empty");
    process.exit(1);
  }
  await writeFile("/home/user/tigris-task/write-denial.log", denial, "utf-8");
  console.log("Captured write denial:", denial);

  // Readonly read
  const getResult = await get("notes/welcome.txt", "string", {
    config: {
      bucket: forkBucket,
      accessKeyId: readonlyCreds.accessKeyId,
      secretAccessKey: readonlyCreds.secretAccessKey,
    },
  });
  if (getResult.error) {
    console.error("Readonly get failed:", stringifyError(getResult.error));
    process.exit(1);
  }
  const body = getResult.data;
  if (body !== "hello readonly") {
    console.error(`Readonly get returned unexpected body: ${JSON.stringify(body)}`);
    process.exit(1);
  }
  await writeFile("/home/user/tigris-task/readback.txt", body, "utf-8");
  console.log("Readback succeeded: notes/welcome.txt =", body);

  console.log("All steps succeeded.");
  process.exit(0);
}

main().catch((err) => {
  console.error("Unhandled error:", stringifyError(err));
  process.exit(1);
});
